import React, { useState, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    green: '#a3e635',
    yellow: '#fbbf24',
    pink: '#f472b6',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const DATA = [20, 40, 55, 75, 95];
const A = 20;
const B = 95;
const DOT_COLORS = ['#38bdf8', '#818cf8', '#a78bfa', '#f472b6', '#fb923c'];

const PRESETS = [
  { label: '0 to 1', c: 0, d: 1 },
  { label: '0 to 10', c: 0, d: 10 },
  { label: '0 to 4 (GPA)', c: 0, d: 4 },
  { label: 'Flip!', c: 1, d: 0 },
];

export default function App() {
  const [c, setC] = useState(0);
  const [d, setD] = useState(1);

  const transformed = useMemo(() => {
    return DATA.map(x => {
      if (B === A) return c;
      return c + (d - c) / (B - A) * (x - A);
    });
  }, [c, d]);

  const SVG_W = 540;
  const SVG_H = 230;
  const PAD = 52;
  const LINE_W = SVG_W - PAD * 2;
  const ORIG_Y = 72;
  const TRANS_Y = 168;

  // Original: map x in [A,B] to SVG x
  const origX = (v) => PAD + (v - A) / (B - A) * LINE_W;

  // Target: always map c to left, d to right (shows proportional spacing)
  const transX = (v) => {
    if (d === c) return PAD + LINE_W / 2;
    return PAD + (v - c) / (d - c) * LINE_W;
  };

  const isFlipped = d < c;
  const scale = B !== A ? (d - c) / (B - A) : 0;
  const midVal = transformed[2];

  const insightText = () => {
    if (d === c) return 'c = d: all values collapse to a single point!';
    if (isFlipped) return 'When d < c: the order REVERSES. Lowest original -> highest output!';
    if (Math.abs(scale) < 0.05) return 'Small range: values are compressed tightly together.';
    if (Math.abs(scale) > 3) return 'Large range: values are stretched far apart.';
    return 'Proportional spacing is always preserved: gaps stay the same relative size.';
  };

  return (
    <div style={{ fontFamily: theme.font, background: theme.colors.background, minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '12px 8px' }}>
      <div style={{ width: '100%', maxWidth: '600px' }}>

        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '12px' }}>
          <div style={{ fontSize: '18px', fontWeight: '700', color: theme.colors.text, marginBottom: '3px' }}>Shift and Scale to Target Range</div>
          <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>Test scores [20, 95] mapped to your chosen range</div>
        </div>

        {/* Preset buttons */}
        <div style={{ display: 'flex', gap: '6px', marginBottom: '10px', justifyContent: 'center', flexWrap: 'wrap' }}>
          {PRESETS.map(p => {
            const active = c === p.c && d === p.d;
            return (
              <button
                key={p.label}
                onClick={() => { setC(p.c); setD(p.d); }}
                style={{
                  padding: '5px 12px', fontSize: '11px', borderRadius: '6px', cursor: 'pointer',
                  border: `1px solid ${active ? theme.colors.primary : theme.colors.border}`,
                  background: active ? '#1a0a35' : theme.colors.surfaceAlt,
                  color: active ? theme.colors.primary : theme.colors.textSecondary,
                  transition: 'all 0.2s',
                }}
              >{p.label}</button>
            );
          })}
        </div>

        {/* Main SVG */}
        <div style={{ background: theme.colors.surface, borderRadius: '12px', padding: '8px 10px 4px', marginBottom: '10px' }}>
          <svg width="100%" viewBox={`0 0 ${SVG_W} ${SVG_H}`} style={{ display: 'block', overflow: 'visible' }}>

            {/* --- ORIGINAL LINE SECTION --- */}
            <text x={SVG_W / 2} y={22} fill={theme.colors.textMuted} fontSize="10" textAnchor="middle" letterSpacing="1">ORIGINAL RANGE</text>

            {/* Range bar */}
            <line x1={PAD} y1={ORIG_Y} x2={SVG_W - PAD} y2={ORIG_Y} stroke="#2a2a2a" strokeWidth="3" strokeLinecap="round" />
            <line x1={PAD} y1={ORIG_Y - 6} x2={PAD} y2={ORIG_Y + 6} stroke="#444" strokeWidth="2" />
            <line x1={SVG_W - PAD} y1={ORIG_Y - 6} x2={SVG_W - PAD} y2={ORIG_Y + 6} stroke="#444" strokeWidth="2" />
            <text x={PAD} y={ORIG_Y - 12} fill={theme.colors.textSecondary} fontSize="10" textAnchor="middle">a={A}</text>
            <text x={SVG_W - PAD} y={ORIG_Y - 12} fill={theme.colors.textSecondary} fontSize="10" textAnchor="middle">b={B}</text>

            {/* Original dots */}
            {DATA.map((v, i) => (
              <g key={i}>
                <circle cx={origX(v)} cy={ORIG_Y} r="14" fill={DOT_COLORS[i]} opacity="0.15" />
                <circle cx={origX(v)} cy={ORIG_Y} r="9" fill={DOT_COLORS[i]} />
                <text x={origX(v)} y={ORIG_Y + 4} fill="#000" fontSize="9" textAnchor="middle" fontWeight="800">{v}</text>
              </g>
            ))}

            {/* --- CONNECTING LINES --- */}
            {DATA.map((v, i) => {
              const tx = transX(transformed[i]);
              const clamped = Math.max(PAD - 20, Math.min(SVG_W - PAD + 20, tx));
              return (
                <line
                  key={i}
                  x1={origX(v)} y1={ORIG_Y + 10}
                  x2={clamped} y2={TRANS_Y - 10}
                  stroke={DOT_COLORS[i]}
                  strokeWidth="1.5"
                  strokeOpacity="0.22"
                  strokeDasharray="4 3"
                />
              );
            })}

            {/* Formula label in middle */}
            <text x={SVG_W / 2} y={(ORIG_Y + TRANS_Y) / 2 + 5} fill={theme.colors.textMuted} fontSize="10" textAnchor="middle">
              f(x) = c + (d - c) / (b - a) * (x - a)
            </text>

            {/* --- TARGET LINE SECTION --- */}
            <text x={SVG_W / 2} y={TRANS_Y - 22} fill={theme.colors.textMuted} fontSize="10" textAnchor="middle" letterSpacing="1">TARGET RANGE</text>

            <line x1={PAD} y1={TRANS_Y} x2={SVG_W - PAD} y2={TRANS_Y} stroke="#1a3520" strokeWidth="3" strokeLinecap="round" />
            <line x1={PAD} y1={TRANS_Y - 6} x2={PAD} y2={TRANS_Y + 6} stroke={theme.colors.green} strokeWidth="2" opacity="0.8" />
            <line x1={SVG_W - PAD} y1={TRANS_Y - 6} x2={SVG_W - PAD} y2={TRANS_Y + 6} stroke={theme.colors.green} strokeWidth="2" opacity="0.8" />
            <text x={PAD} y={TRANS_Y + 18} fill={theme.colors.green} fontSize="10" textAnchor="middle">c={c}</text>
            <text x={SVG_W - PAD} y={TRANS_Y + 18} fill={theme.colors.green} fontSize="10" textAnchor="middle">d={d}</text>

            {/* Transformed dots */}
            {transformed.map((v, i) => {
              const tx = transX(v);
              const clamped = Math.max(PAD - 20, Math.min(SVG_W - PAD + 20, tx));
              const outOfBounds = tx < PAD - 20 || tx > SVG_W - PAD + 20;
              return (
                <g key={i}>
                  <circle cx={clamped} cy={TRANS_Y} r="14" fill={DOT_COLORS[i]} opacity="0.15" style={{ transition: 'cx 0.35s ease' }} />
                  <circle cx={clamped} cy={TRANS_Y} r="9" fill={DOT_COLORS[i]} opacity={outOfBounds ? 0.4 : 1} style={{ transition: 'cx 0.35s ease' }} />
                  <text x={clamped} y={TRANS_Y + 4} fill="#000" fontSize="8" textAnchor="middle" fontWeight="800" style={{ transition: 'x 0.35s ease' }}>
                    {Math.abs(v) >= 100 ? v.toFixed(0) : v.toFixed(2)}
                  </text>
                </g>
              );
            })}

            {/* Spacer */}
            <rect x={0} y={TRANS_Y + 25} width={SVG_W} height={10} fill="none" />
          </svg>
        </div>

        {/* Sliders */}
        <div style={{ background: theme.colors.surface, borderRadius: '12px', padding: '12px 14px', marginBottom: '10px' }}>
          <div style={{ display: 'flex', gap: '16px', alignItems: 'center', marginBottom: '10px' }}>
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px' }}>
                <span style={{ fontSize: '12px', color: theme.colors.green }}>c (target min)</span>
                <span style={{ fontSize: '13px', color: theme.colors.text, fontWeight: '700' }}>{c}</span>
              </div>
              <input
                type="range" min="-5" max="15" step="0.5" value={c}
                onChange={e => setC(parseFloat(e.target.value))}
                style={{ width: '100%', accentColor: theme.colors.green, cursor: 'pointer' }}
              />
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px' }}>
                <span style={{ fontSize: '12px', color: theme.colors.green }}>d (target max)</span>
                <span style={{ fontSize: '13px', color: theme.colors.text, fontWeight: '700' }}>{d}</span>
              </div>
              <input
                type="range" min="-5" max="15" step="0.5" value={d}
                onChange={e => setD(parseFloat(e.target.value))}
                style={{ width: '100%', accentColor: theme.colors.green, cursor: 'pointer' }}
              />
            </div>
          </div>

          {/* Live formula computation */}
          <div style={{ background: theme.colors.surfaceAlt, borderRadius: '8px', padding: '8px 12px', fontSize: '12px' }}>
            <div style={{ color: theme.colors.textSecondary, marginBottom: '3px', fontSize: '11px' }}>Live computation for x = 55 (middle score):</div>
            <div style={{ color: theme.colors.primary, fontFamily: theme.font }}>
              f(55) = {c} + ({d} - {c}) / ({B} - {A}) * (55 - {A})
              {' = '}
              <span style={{ color: theme.colors.green, fontWeight: '700' }}>
                {(c + (d - c) / (B - A) * (55 - A)).toFixed(4)}
              </span>
            </div>
          </div>
        </div>

        {/* Insight */}
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: '8px', padding: '9px 14px',
          fontSize: '12px', color: theme.colors.textSecondary,
          borderLeft: `3px solid ${isFlipped ? theme.colors.pink : d === c ? theme.colors.yellow : theme.colors.primary}`
        }}>
          <span style={{ color: isFlipped ? theme.colors.pink : d === c ? theme.colors.yellow : theme.colors.primary, fontWeight: '600' }}>
            {isFlipped ? 'Reversal: ' : d === c ? 'Edge case: ' : 'Key insight: '}
          </span>
          {insightText()}
        </div>

      </div>
    </div>
  );
}
